INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118061, 1, 2834, 20063115, 91002, "青空の下で謁見", "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 7, "フリーマーケット会場", 0, 40, "ペコリーヌとの出会い", 8, 10118, 2);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118062, 1, 2835, 20063115, 91002, "未来の騎空団\nマスコット？", "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 7, "フリーマーケット会場", 0, 40, "マホとの出会い", 8, 10118, 2);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118063, 1, 2837, 20063115, 91002, "お嬢さまからの\n緊急依頼", "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 7, "ランドソル市街地", 0, 40, "アキノとの出会い", 8, 10118, 2);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118064, 1, 4108402, 20063115, 91002, "黄金色の悩みごと", "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 18, "フリーマーケット会場", 0, 40, "ジュンとの出会い", 8, 10118, 2);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118065, 1, 4107402, 20063115, 91002, "白熱！　格闘大会！", "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 18, "フリーマーケット会場", 0, 40, "カオリとの出会い", 8, 10118, 2);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118066, 1, 9000227, 20063115, 91002, "祭り太鼓はオーエドの華", "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 16, "オーエド町", 1, 40, "ニノンとの出会い", 8, 10118, 2);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118067, 1, 2101181, 20063115, 91002, "人気者は遅れて\nやってくる", "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 19, "フリーマーケット会場", 0, 40, "スズナとの出会い", 8, 10118, 3);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118068, 1, 4109402, 20063115, 91002, "巫女・ミーツ・魔法少女", "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 18, "ランドソル市街地", 0, 40, "ナナカとの出会い", 8, 10118, 3);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118069, 1, 4305402, 20063115, 91002, "ネズ耳は二度なくなる", "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 18, "フリーマーケット会場", 0, 40, "キャル＆コッコロとの出会い", 8, 10118, 3);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118070, 1, 4101402, 20063115, 91002, "この出会いにカンパイ！", "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 18, "ランドソル市街地", 0, 40, "ユカリとの出会い", 8, 10118, 3);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118071, 1, 4106402, 20063115, 91002, "陰陽アンサンブル", "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 18, "ランドソル市街地", 0, 40, "アオイとの出会い", 8, 10118, 3);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118072, 1, 2836, 20063115, 91002, "運試し十番勝負！", "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 7, "フリーマーケット会場", 1, 40, "シノブとの出会い", 8, 10118, 3);
INSERT INTO `v1_2b2b6a7eb30db423bfa9ea7d4feadfab9fad672a1d75c147d50529e5f3c0a74c` VALUES (5118600, 0, 0, 20063115, 0, "彼女たちの新たな日常", 0, 0, 0, 0, 0, "オープニング", 0, 10118, 1);
